import{_ as t,c as a,o,ax as d}from"./chunks/framework.DHqKNX4U.js";const u=JSON.parse('{"title":"Retention Policy: Backend Implementation","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-policy/retention-service.md","filePath":"enterprise/retention-policy/retention-service.md"}'),i={name:"enterprise/retention-policy/retention-service.md"};function r(c,e,n,l,s,h){return o(),a("div",null,e[0]||(e[0]=[d('<h1 id="retention-policy-backend-implementation" tabindex="-1">Retention Policy: Backend Implementation <a class="header-anchor" href="#retention-policy-backend-implementation" aria-label="Permalink to &quot;Retention Policy: Backend Implementation&quot;">​</a></h1><p>The backend implementation of the retention policy engine is handled by the <code>RetentionService</code>, located in <code>packages/enterprise/src/modules/retention-policy/RetentionService.ts</code>. This service encapsulates all CRUD operations for policies and the core evaluation engine that determines which policies apply to a given email.</p><h2 id="database-schema" tabindex="-1">Database Schema <a class="header-anchor" href="#database-schema" aria-label="Permalink to &quot;Database Schema&quot;">​</a></h2><p>The <code>retention_policies</code> table is defined in <code>packages/backend/src/database/schema/compliance.ts</code> using Drizzle ORM:</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>uuid</code> (PK)</td><td>Auto-generated unique identifier.</td></tr><tr><td><code>name</code></td><td><code>text</code> (unique, not null)</td><td>Human-readable policy name.</td></tr><tr><td><code>description</code></td><td><code>text</code></td><td>Optional description.</td></tr><tr><td><code>priority</code></td><td><code>integer</code> (not null)</td><td>Priority for ordering. Lower = higher priority.</td></tr><tr><td><code>retention_period_days</code></td><td><code>integer</code> (not null)</td><td>Number of days to retain matching emails.</td></tr><tr><td><code>action_on_expiry</code></td><td><code>enum</code> (not null)</td><td>Action on expiry (<code>delete_permanently</code>).</td></tr><tr><td><code>is_enabled</code></td><td><code>boolean</code> (default: true)</td><td>Whether the policy is active.</td></tr><tr><td><code>conditions</code></td><td><code>jsonb</code></td><td>Serialized <code>RetentionRuleGroup</code> or null (null = matches all).</td></tr><tr><td><code>ingestion_scope</code></td><td><code>jsonb</code></td><td>Array of ingestion source UUIDs or null (null = all sources).</td></tr><tr><td><code>created_at</code></td><td><code>timestamptz</code></td><td>Creation timestamp.</td></tr><tr><td><code>updated_at</code></td><td><code>timestamptz</code></td><td>Last update timestamp.</td></tr></tbody></table><h2 id="crud-operations" tabindex="-1">CRUD Operations <a class="header-anchor" href="#crud-operations" aria-label="Permalink to &quot;CRUD Operations&quot;">​</a></h2><p>The <code>RetentionService</code> class provides the following methods:</p><h3 id="createpolicy-data-actorid-actorip" tabindex="-1"><code>createPolicy(data, actorId, actorIp)</code> <a class="header-anchor" href="#createpolicy-data-actorid-actorip" aria-label="Permalink to &quot;`createPolicy(data, actorId, actorIp)`&quot;">​</a></h3><p>Inserts a new policy into the database and creates an audit log entry with action type <code>CREATE</code> and target type <code>RetentionPolicy</code>. The audit log details include the policy name, retention period, priority, action on expiry, and ingestion scope.</p><h3 id="getpolicies" tabindex="-1"><code>getPolicies()</code> <a class="header-anchor" href="#getpolicies" aria-label="Permalink to &quot;`getPolicies()`&quot;">​</a></h3><p>Returns all policies ordered by priority ascending. The raw database rows are mapped through <code>mapDbPolicyToType()</code>, which converts the DB column <code>isEnabled</code> to the shared type field <code>isActive</code> and normalizes date fields to ISO strings.</p><h3 id="getpolicybyid-id" tabindex="-1"><code>getPolicyById(id)</code> <a class="header-anchor" href="#getpolicybyid-id" aria-label="Permalink to &quot;`getPolicyById(id)`&quot;">​</a></h3><p>Returns a single policy by UUID, or null if not found.</p><h3 id="updatepolicy-id-data-actorid-actorip" tabindex="-1"><code>updatePolicy(id, data, actorId, actorIp)</code> <a class="header-anchor" href="#updatepolicy-id-data-actorid-actorip" aria-label="Permalink to &quot;`updatePolicy(id, data, actorId, actorIp)`&quot;">​</a></h3><p>Partially updates a policy — only fields present in the DTO are modified. The <code>updatedAt</code> timestamp is always set to the current time. An audit log entry is created with action type <code>UPDATE</code>, recording which fields were changed.</p><p>Throws an error if the policy is not found.</p><h3 id="deletepolicy-id-actorid-actorip" tabindex="-1"><code>deletePolicy(id, actorId, actorIp)</code> <a class="header-anchor" href="#deletepolicy-id-actorid-actorip" aria-label="Permalink to &quot;`deletePolicy(id, actorId, actorIp)`&quot;">​</a></h3><p>Deletes a policy by UUID and creates an audit log entry with action type <code>DELETE</code>, recording the deleted policy&#39;s name. Returns <code>false</code> if the policy was not found.</p><h2 id="evaluation-engine" tabindex="-1">Evaluation Engine <a class="header-anchor" href="#evaluation-engine" aria-label="Permalink to &quot;Evaluation Engine&quot;">​</a></h2><p>The evaluation engine is the core logic that determines which policies apply to a given email. It is used by both the lifecycle worker (for automated enforcement) and the policy simulator endpoint (for testing).</p><h3 id="evaluateemail-metadata" tabindex="-1"><code>evaluateEmail(metadata)</code> <a class="header-anchor" href="#evaluateemail-metadata" aria-label="Permalink to &quot;`evaluateEmail(metadata)`&quot;">​</a></h3><p>This is the primary evaluation method. It accepts email metadata and returns:</p><ul><li><code>appliedRetentionDays</code>: The longest matching retention period (max-duration-wins).</li><li><code>matchingPolicyIds</code>: UUIDs of all policies that matched.</li><li><code>actionOnExpiry</code>: Always <code>&quot;delete_permanently&quot;</code> in the current implementation.</li></ul><p>The evaluation flow:</p><ol><li><strong>Fetch active policies:</strong> Queries all policies where <code>isEnabled = true</code>.</li><li><strong>Ingestion scope check:</strong> For each policy with a non-null <code>ingestionScope</code>, the email&#39;s <code>ingestionSourceId</code> must be included in the scope array. If not, the policy is skipped.</li><li><strong>Condition evaluation:</strong> If the policy has no conditions (<code>null</code>), it matches all emails within scope. Otherwise, the condition rule group is evaluated.</li><li><strong>Max-duration-wins:</strong> If multiple policies match, the longest <code>retentionPeriodDays</code> is used.</li><li><strong>Zero means no match:</strong> A return value of <code>appliedRetentionDays = 0</code> indicates no policy matched — the lifecycle worker will not delete the email.</li></ol><h3 id="evaluaterulegroup-group-metadata" tabindex="-1"><code>_evaluateRuleGroup(group, metadata)</code> <a class="header-anchor" href="#evaluaterulegroup-group-metadata" aria-label="Permalink to &quot;`_evaluateRuleGroup(group, metadata)`&quot;">​</a></h3><p>Evaluates a <code>RetentionRuleGroup</code> using AND or OR logic:</p><ul><li><strong>AND:</strong> Every rule in the group must pass.</li><li><strong>OR:</strong> At least one rule must pass.</li><li>An empty rules array evaluates to <code>true</code>.</li></ul><h3 id="evaluaterule-rule-metadata" tabindex="-1"><code>_evaluateRule(rule, metadata)</code> <a class="header-anchor" href="#evaluaterule-rule-metadata" aria-label="Permalink to &quot;`_evaluateRule(rule, metadata)`&quot;">​</a></h3><p>Evaluates a single rule against the email metadata. All string comparisons are case-insensitive (both sides are lowercased before comparison). The behavior depends on the field:</p><table tabindex="0"><thead><tr><th>Field</th><th>Behavior</th></tr></thead><tbody><tr><td><code>sender</code></td><td>Compares against the sender email address.</td></tr><tr><td><code>recipient</code></td><td>Passes if <strong>any</strong> recipient matches the operator.</td></tr><tr><td><code>subject</code></td><td>Compares against the email subject.</td></tr><tr><td><code>attachment_type</code></td><td>Passes if <strong>any</strong> attachment file extension matches (e.g., <code>.pdf</code>).</td></tr></tbody></table><h3 id="applyoperator-haystack-operator-needle" tabindex="-1"><code>_applyOperator(haystack, operator, needle)</code> <a class="header-anchor" href="#applyoperator-haystack-operator-needle" aria-label="Permalink to &quot;`_applyOperator(haystack, operator, needle)`&quot;">​</a></h3><p>Applies a string-comparison operator between two pre-lowercased strings:</p><table tabindex="0"><thead><tr><th>Operator</th><th>Implementation</th></tr></thead><tbody><tr><td><code>equals</code></td><td><code>haystack === needle</code></td></tr><tr><td><code>not_equals</code></td><td><code>haystack !== needle</code></td></tr><tr><td><code>contains</code></td><td><code>haystack.includes(needle)</code></td></tr><tr><td><code>not_contains</code></td><td><code>!haystack.includes(needle)</code></td></tr><tr><td><code>starts_with</code></td><td><code>haystack.startsWith(needle)</code></td></tr><tr><td><code>ends_with</code></td><td><code>haystack.endsWith(needle)</code></td></tr><tr><td><code>domain_match</code></td><td><code>haystack.endsWith(&#39;@&#39; + needle)</code> (auto-prepends <code>@</code> if missing)</td></tr><tr><td><code>regex_match</code></td><td><code>new RegExp(needle, &#39;i&#39;).test(haystack)</code> with safety guards (see below)</td></tr></tbody></table><h3 id="security-regex-match-safeguards" tabindex="-1">Security: <code>regex_match</code> Safeguards <a class="header-anchor" href="#security-regex-match-safeguards" aria-label="Permalink to &quot;Security: `regex_match` Safeguards&quot;">​</a></h3><p>The <code>regex_match</code> operator includes protections against Regular Expression Denial of Service (ReDoS):</p><ol><li><strong>Length limit:</strong> Patterns exceeding 200 characters (<code>MAX_REGEX_LENGTH</code>) are rejected and treated as non-matching. A warning is logged.</li><li><strong>Error handling:</strong> Invalid regex syntax is caught in a try/catch block and treated as non-matching. A warning is logged.</li><li><strong>Flags:</strong> Only the case-insensitive flag (<code>i</code>) is used. Global and multiline flags are excluded to prevent stateful matching bugs.</li></ol><h2 id="request-validation" tabindex="-1">Request Validation <a class="header-anchor" href="#request-validation" aria-label="Permalink to &quot;Request Validation&quot;">​</a></h2><p>The <code>RetentionPolicyController</code> (<code>retention-policy.controller.ts</code>) validates all incoming requests using Zod schemas before passing data to the service:</p><table tabindex="0"><thead><tr><th>Constraint</th><th>Limit</th></tr></thead><tbody><tr><td>Policy name</td><td>1–255 characters.</td></tr><tr><td>Description</td><td>Max 1000 characters.</td></tr><tr><td>Priority</td><td>Positive integer (≥ 1).</td></tr><tr><td>Retention period</td><td>Positive integer (≥ 1 day).</td></tr><tr><td>Rules per group</td><td>Max 50.</td></tr><tr><td>Rule value</td><td>1–500 characters.</td></tr><tr><td>Ingestion scope entries</td><td>Each must be a valid UUID. Empty arrays are coerced to <code>null</code>.</td></tr><tr><td>Evaluate — sender</td><td>Max 500 characters.</td></tr><tr><td>Evaluate — recipients</td><td>Max 500 entries, each max 500 characters.</td></tr><tr><td>Evaluate — subject</td><td>Max 2000 characters.</td></tr><tr><td>Evaluate — attachment types</td><td>Max 100 entries, each max 50 characters.</td></tr></tbody></table><h2 id="module-registration" tabindex="-1">Module Registration <a class="header-anchor" href="#module-registration" aria-label="Permalink to &quot;Module Registration&quot;">​</a></h2><p>The <code>RetentionPolicyModule</code> (<code>retention-policy.module.ts</code>) implements the <code>ArchiverModule</code> interface and registers the API routes at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/{api.version}/enterprise/retention-policy</span></span></code></pre></div><p>All routes are protected by:</p><ol><li><code>requireAuth</code> — Ensures the request includes a valid authentication token.</li><li><code>featureEnabled(OpenArchiverFeature.RETENTION_POLICY)</code> — Ensures the enterprise license includes the retention policy feature.</li><li><code>requirePermission(&#39;manage&#39;, &#39;all&#39;)</code> — Ensures the user has administrative permissions.</li></ol>',45)]))}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
